          "name": "Script",
          "script": "(function execute() {\n\n    try {\n\n        var query = \"\";\n\n        // ✅ Safe read from VA input\n        if (typeof vaInputs !== 'undefined' && vaInputs.user_input) {\n            query = vaInputs.user_input;\n        }\n\n        // ✅ Fallback (VERY IMPORTANT)\n        if ((!query || query === \"\") && typeof vaVars !== 'undefined' && vaVars._topic_current_message) {\n            query = vaVars._topic_current_message;\n        }\n\n        // ✅ Final fallback to avoid crash\n        if (!query) {\n            query = \"payout\";\n        }\n\n        var userId = gs.getUserID();\n\n        var service = new x_ctans_incentnow.IncentNowCopilotService();\n        var response = service.getResponse(query, userId);\n\n        vaVars.gptResponse = response;\n\n    } catch (ex) {\n\n        gs.error(\"FINAL VA ERROR: \" + ex.message);\n\n        vaVars.gptResponse = \"⚠️ Something went wrong. Please try again.\";\n    }\n\n})();",
